{"code":"prs = github.list_pull_requests(state="open")
all_count = len(prs)
repo_counts = {}
for pr in prs:
    repo = pr['repo']
    repo_counts[repo] = repo_counts.get(repo, 0) + 1
max_repo = max(repo_counts, key=repo_counts.get)
max_count = repo_counts[max_repo]
(all_count, max_repo, max_count)"}
